import Tags from "./Tags";
import decode from "./lib/decode-html";
import styles from "./Post.module.css";
import { DateTime } from "luxon";

function Post(props) {
	const { post } = props;

	const dateTime = DateTime.fromISO(post.date);
	const date = dateTime.toLocaleString(DateTime.DATETIME_SHORT);

	const diff = dateTime.diffNow("days").toObject();
	const dateOffset = diff.days > -10 ? dateTime.toRelative() : null;

	return (
		<div key={post.id} className={styles.Post}>
			<div className={styles.imageWrapper}>
				<a href={post.link} target="_blank" rel="noreferrer">
					<img
						src={"/" + post.image}
						alt={post.title}
						className={styles.Image}
					/>
				</a>
				{dateOffset && (
					<div className={styles.DateMark}>{dateOffset}</div>
				)}
			</div>
			<h2 className={styles.PostHeader}>
				<a href={post.link} target="_blank" rel="noreferrer">
					{decode(post.title)}
				</a>
			</h2>
			<div className={styles.Content}>{decode(post.content)}</div>
			<Tags tags={post.tags} />
			<div className={styles.Footer}>
				<ul>
					<li>
						<span className={styles.DateInfo}>{date}</span>
					</li>
					<li>
						<a
							href={post.link}
							target="_blank"
							rel="noreferrer"
							className={styles.readMore}
						>
							더 보기
						</a>
					</li>
				</ul>
			</div>
		</div>
	);
}

export default Post;
